input.newString:
export async function POST(request) {
  const raw = await request.text()
  const url = request.url
  if (!url.includes('/users')) return json({ error: 'invalid endpoint' }, 400)
  try {
    const body = JSON.parse(raw)
    if (!body.email || !body.email.includes('@')) return json({ error: 'invalid email' }, 400)
    if (typeof body.name === 'undefined') return json({ error: 'missing field name' }, 400)
    return json({ id: 'user_1', email: body.email, name: body.name }, 201)
  } catch {
    return json({ error: 'invalid payload' }, 400)
  }
}

